import React from "react";
import "./MenuItem.css";

function MenuItem({ name, description, price, addToCart }) {
  return (
    <div className="MenuItem">
      <h3>{name}</h3>
      <p>
        {description}
        <br />
        Price: ${price}
      </p>
      <button onClick={addToCart} className="AddToCartButton">
        Add to Cart
      </button>
    </div>
  );
}

export default MenuItem;
